import{_ as a,o as e,c as i,a2 as t}from"./chunks/framework.DdLJaIXX.js";const k=JSON.parse('{"title":"Relay MCP Server Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/relay.md","filePath":"guide/relay.md"}'),n={name:"guide/relay.md"};function l(r,s,h,o,p,c){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="relay-mcp-server-guide" tabindex="-1">Relay MCP Server Guide <a class="header-anchor" href="#relay-mcp-server-guide" aria-label="Permalink to &quot;Relay MCP Server Guide&quot;">​</a></h1><p>Relay enables GPU Anywhere access — remote MCP connections to any worker, even behind NAT — via an E2E encrypted cloud WebSocket bridge.</p><h2 id="what-is-relay" tabindex="-1">What is Relay? <a class="header-anchor" href="#what-is-relay" aria-label="Permalink to &quot;What is Relay?&quot;">​</a></h2><p>Relay is the NAT traversal layer that makes GPU Anywhere possible. A worker running <code>cq serve</code> opens a persistent WebSocket connection to the relay server. Remote MCP clients (Claude Code, other agents) connect through HTTPS. The relay bridges the two without requiring inbound ports or firewall changes on the worker — zero config, any network.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Claude Code / Client</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │  HTTPS  (MCP over HTTP)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  cq-relay.fly.dev</span></span>
<span class="line"><span>  relay server (cloud)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │  WSS  (persistent WebSocket)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  Worker machine</span></span>
<span class="line"><span>  (cq serve, behind NAT)</span></span></code></pre></div><p><strong>Key properties:</strong></p><ul><li>No inbound ports needed on the worker — outbound WSS only.</li><li>E2E encrypted: session-authenticated via <code>cq serve</code>, no manual token management.</li><li>MCP protocol is proxied transparently — all 118+ cq MCP tools are accessible remotely.</li><li>Works on any OS, any network — home lab, cloud VM, or corporate network behind NAT.</li></ul><hr><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="_1-authenticate" tabindex="-1">1. Authenticate <a class="header-anchor" href="#_1-authenticate" aria-label="Permalink to &quot;1. Authenticate&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>This stores a session JWT at <code>~/.c4/session.json</code>. Relay reads this automatically — no extra configuration needed.</p><h3 id="_2-start-cq-serve" tabindex="-1">2. Start cq serve <a class="header-anchor" href="#_2-start-cq-serve" aria-label="Permalink to &quot;2. Start cq serve&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>On startup, <code>cq serve</code> connects to the relay server and registers the worker. The worker ID is printed in the output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[relay] connected  worker_id=wkr_abc123  url=wss://cq-relay.fly.dev/ws</span></span>
<span class="line"><span>[relay] MCP endpoint ready  https://cq-relay.fly.dev/w/wkr_abc123/mcp</span></span></code></pre></div><h3 id="_3-check-relay-status" tabindex="-1">3. Check relay status <a class="header-anchor" href="#_3-check-relay-status" aria-label="Permalink to &quot;3. Check relay status&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> relay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Relay:    connected</span></span>
<span class="line"><span>Worker:   wkr_abc123</span></span>
<span class="line"><span>MCP URL:  https://cq-relay.fly.dev/w/wkr_abc123/mcp</span></span>
<span class="line"><span>Latency:  12ms</span></span></code></pre></div><hr><h2 id="connecting-external-mcp-clients" tabindex="-1">Connecting External MCP Clients <a class="header-anchor" href="#connecting-external-mcp-clients" aria-label="Permalink to &quot;Connecting External MCP Clients&quot;">​</a></h2><p>Any MCP-compatible client can connect to the worker through relay.</p><h3 id="mcp-url-format" tabindex="-1">MCP URL format <a class="header-anchor" href="#mcp-url-format" aria-label="Permalink to &quot;MCP URL format&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cq-relay.fly.dev/w/{worker_id}/mcp</span></span></code></pre></div><p>Replace <code>{worker_id}</code> with the value from <code>cq relay status</code>.</p><h3 id="claude-code-mcp-json" tabindex="-1">Claude Code <code>.mcp.json</code> <a class="header-anchor" href="#claude-code-mcp-json" aria-label="Permalink to &quot;Claude Code \`.mcp.json\`&quot;">​</a></h3><p><code>cq serve</code> exposes a local proxy that handles authentication automatically. Use the localhost URL — no tokens needed in the config file:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;my-worker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://localhost:51822/w/wkr_abc123/mcp&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The serve port defaults to <code>51822</code>. Check the actual port with:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> relay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Shows MCP URL including port</span></span></code></pre></div><p><code>cq init</code> automatically writes the correct localhost URL when setting up worker entries — no manual editing required.</p><h3 id="other-mcp-clients" tabindex="-1">Other MCP clients <a class="header-anchor" href="#other-mcp-clients" aria-label="Permalink to &quot;Other MCP clients&quot;">​</a></h3><p>Any client that supports MCP Streamable HTTP (JSON-RPC 2.0 over HTTP) works. Set:</p><ul><li><strong>URL</strong>: <code>http://localhost:{servePort}/w/{worker_id}/mcp</code></li><li><strong>Auth</strong>: none — <code>cq serve</code> handles session auth transparently</li><li><strong>Method</strong>: POST with <code>Content-Type: application/json</code></li></ul><hr><h2 id="large-file-transfer-cq-transfer" tabindex="-1">Large File Transfer: cq transfer <a class="header-anchor" href="#large-file-transfer-cq-transfer" aria-label="Permalink to &quot;Large File Transfer: cq transfer&quot;">​</a></h2><p>For large payloads (datasets, model checkpoints), use peer-to-peer transfer instead of relay.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># On worker — share a file</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./model.ckpt</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Outputs: cq transfer recv &lt;transfer-id&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># On client — receive</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">transfer-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><code>cq transfer</code> uses WebRTC-based P2P: the relay server brokers the initial handshake, then data flows directly between the two machines (no relay bottleneck for large transfers).</p><hr><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><p><code>cq serve</code> manages authentication automatically. The local proxy at <code>http://localhost:{servePort}</code> handles session tokens — MCP clients connect without any credentials in their config.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MCP client → localhost proxy (cq serve)</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    │  session-authenticated WSS</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>             cq-relay.fly.dev</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>             Worker machine</span></span></code></pre></div><h3 id="what-s-protected" tabindex="-1">What&#39;s protected <a class="header-anchor" href="#what-s-protected" aria-label="Permalink to &quot;What&#39;s protected&quot;">​</a></h3><ul><li><strong>Worker-to-relay</strong> connection: authenticated with the worker&#39;s session (managed by <code>cq serve</code>).</li><li><strong>Local proxy access</strong>: bound to the local machine — not exposed externally.</li><li><strong>Worker isolation</strong>: each worker ID is bound to its owner&#39;s user account. A user cannot access another user&#39;s worker via relay.</li></ul><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="relay-not-connecting" tabindex="-1">Relay not connecting <a class="header-anchor" href="#relay-not-connecting" aria-label="Permalink to &quot;Relay not connecting&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> relay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # Check connection state</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Re-authenticate if session expired</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # Restart — relay reconnects automatically on startup</span></span></code></pre></div><p>Check that the worker can reach the relay server:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://cq-relay.fly.dev/health</span></span></code></pre></div><h3 id="_401-unauthorized" tabindex="-1">401 Unauthorized <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;401 Unauthorized&quot;">​</a></h3><p>The session is expired or invalid.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Refresh session</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # Restart to pick up the new session</span></span></code></pre></div><h3 id="workers-0-in-relay-status" tabindex="-1"><code>workers: 0</code> in relay status <a class="header-anchor" href="#workers-0-in-relay-status" aria-label="Permalink to &quot;\`workers: 0\` in relay status&quot;">​</a></h3><p>The worker is not registered. Possible causes:</p><ol><li><code>cq serve</code> is not running — start it.</li><li>Auth failed on startup — check <code>cq auth login</code>.</li><li>Network issue — check outbound WSS (port 443) to <code>cq-relay.fly.dev</code>.</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check serve logs for relay errors</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> relay</span></span></code></pre></div><h3 id="high-latency-through-relay" tabindex="-1">High latency through relay <a class="header-anchor" href="#high-latency-through-relay" aria-label="Permalink to &quot;High latency through relay&quot;">​</a></h3><p>Relay adds ~10–50ms round-trip overhead (relay server location dependent). For latency-sensitive workloads:</p><ul><li>Use <code>cq transfer</code> for large data.</li><li>Consider running cq serve on a machine with direct network access.</li><li>Self-host relay (contact support for <code>cq-relay</code> source).</li></ul>`,63)])])}const u=a(n,[["render",l]]);export{k as __pageData,u as default};
